const ZH = {}, EN = {}, FLAG = {}, N2C = {}, EMOJI = {};
const norm = s => (s || "").toLowerCase().replace(/[^a-z]/g, "");
// code → emoji 国旗（手机端微信原生渲染；特殊地区用旗帜 emoji）
function codeToEmoji(c){
  const special = { "gb-sct":"🏴\u{E0067}\u{E0062}\u{E0073}\u{E0063}\u{E0074}\u{E007F}", "eng":"🏴\u{E0067}\u{E0062}\u{E0065}\u{E006E}\u{E0067}\u{E007F}" };
  if (special[c]) return special[c];
  const cc = c.slice(0,2).toUpperCase();
  if (cc.length !== 2 || /[^A-Z]/.test(cc)) return "🏳️";
  return String.fromCodePoint(...[...cc].map(ch => 0x1F1E6 + ch.charCodeAt(0) - 65));
}
T.forEach(([c, zh, al]) => { ZH[c]=zh; EN[c]=al[0]; FLAG[c]=(c==="eng"?"gb-eng":c); EMOJI[c]=codeToEmoji(c); al.forEach(a=>N2C[norm(a)]=c); N2C[norm(zh)]=c; });

